import{_ as e,o as t,c as a,a2 as r}from"./chunks/framework.DTa47_fH.js";const g=JSON.parse('{"title":"Portfolio Operations","description":"","frontmatter":{},"headers":[],"relativePath":"portfolio.md","filePath":"portfolio.md"}'),i={name:"portfolio.md"};function s(n,o,l,p,d,h){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="portfolio-operations" tabindex="-1">Portfolio Operations <a class="header-anchor" href="#portfolio-operations" aria-label="Permalink to &quot;Portfolio Operations&quot;">​</a></h1><p>Portfolio Operations provides an aggregate view across all applications in your workspace, enabling you to compare findings, plan migration waves, and produce a portfolio-level compliance picture for executive and regulatory audiences.</p><p>This feature is available in the <strong>Enterprise</strong> edition.</p><p>Access from the TUI main menu by pressing <strong>7</strong>.</p><hr><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>Where individual application assessments give you deep-dive findings for one application, Portfolio Operations combines them into a single coherent view:</p><ul><li><strong>Aggregate risk register</strong> -- all risks from all applications in one ranked list.</li><li><strong>Cross-app compliance matrix</strong> -- every framework control mapped against every application so you can see which controls are consistently passing and where portfolio-wide gaps exist.</li><li><strong>Migration wave planning</strong> -- applications grouped and sequenced for migration based on their 7R verdicts, risk scores, and dependency relationships.</li><li><strong>Portfolio BI export</strong> -- the portfolio star schema that feeds the Power BI portfolio dashboard (aggregated across all apps in <code>wsp/exports/latest/star/</code>).</li></ul><hr><h2 id="running-a-portfolio-export" tabindex="-1">Running a portfolio export <a class="header-anchor" href="#running-a-portfolio-export" aria-label="Permalink to &quot;Running a portfolio export&quot;">​</a></h2><p>After you have assessed all applications in the workspace, generate the portfolio export:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao export --portfolio</span></span></code></pre></div><p>This aggregates the individual star-schema bundles into a single portfolio-level export ready for the Power BI portfolio template.</p><hr><h2 id="portfolio-power-bi-dashboard" tabindex="-1">Portfolio Power BI dashboard <a class="header-anchor" href="#portfolio-power-bi-dashboard" aria-label="Permalink to &quot;Portfolio Power BI dashboard&quot;">​</a></h2><p>The portfolio dashboard gives stakeholders a single view of the entire estate:</p><table tabindex="0"><thead><tr><th>Page</th><th>What it shows</th></tr></thead><tbody><tr><td>Portfolio Overview</td><td>Total apps, average coverage, apps with critical risk, 7R distribution</td></tr><tr><td>Compliance</td><td>Cross-app compliance matrix by framework</td></tr><tr><td>Signals</td><td>Portfolio signal browser</td></tr><tr><td>Auditor Roll-up</td><td>Per-app rationale coverage and cross-app compliance status</td></tr><tr><td>Run Stats</td><td>Aggregate timing and LLM cost</td></tr></tbody></table><p>See <a href="./export-bi">Export BI</a> for instructions on connecting the dashboard template to your portfolio export.</p><hr><h2 id="wave-planning" tabindex="-1">Wave planning <a class="header-anchor" href="#wave-planning" aria-label="Permalink to &quot;Wave planning&quot;">​</a></h2><p>Portfolio Operations groups applications into migration waves based on:</p><ul><li><strong>Risk score</strong> -- high-risk applications are typically addressed first.</li><li><strong>7R verdict</strong> -- applications with the same strategy are grouped together.</li><li><strong>Dependencies</strong> -- applications that depend on each other are placed in the same wave or in immediately consecutive waves.</li></ul><p>Wave assignments are visible in the portfolio Power BI dashboard and are included in the portfolio export bundle for use in external planning tools.</p>',23)])])}const f=e(i,[["render",s]]);export{g as __pageData,f as default};
